/* Map skill names → component */
export const SKILL_ICONS: Record<string, React.FC<IconProps>> = {
    JavaScript: JavascriptIcon,
    TypeScript: TypescriptIcon,
    Dart: DartIcon,
    PHP: PhpIcon,
    Python: PythonIcon,
    "C / C++": CplusplusIcon,
    Java: JavaIcon,
    "C#": CsharpIcon,
    React: ReactIcon,
    "Next.js": NextjsIcon,
    "Tailwind CSS": TailwindIcon,
    Flutter: FlutterIcon,
    Xamarin: DotnetIcon,
    "Node.js": NodeIcon,
    Express: ExpressIcon,
    Laravel: LaravelIcon,
    MongoDB: MongodbIcon,
    Firebase: FirebaseIcon,
    MySQL: MysqlIcon,
    Firestore: FirebaseIcon,
    FCM: FirebaseIcon,
    Provider: FlutterIcon,
    ".NET": DotnetIcon,
};

export function SkillIcon({
    name,
    className = "h-3.5 w-3.5",
}: {
    name: string;
    className?: string;
}) {
    const Icon = SKILL_ICONS[name];
    if (!Icon) return null;
    return <Icon className={className} />;
}
